import copy

def difference(d1, d2, level=-1):

    if level == 0:
        return {}

    diff = {}
    for key in d1:
        if key not in d2:
            diff[key] = copy.deepcopy(d1[key])
        elif isinstance(d1[key], dict) and isinstance(d2[key], dict) and (level == -1 or level > 1):
