def _extract_number_and_supplment_from_issue_element(issue):

    # Rimuovi eventuali spazi bianchi all'inizio e alla fine
    issue = issue.strip()

    # Cerca un numero seguito da un supplemento (es. "123A")
    if issue and issue[-1].isalpha():
        number = issue[:-1]
        supplement = issue[-1]
        try:
            number = int(number)
            return number, supplement
        except ValueError:
            pass

    # Se non c'è un supplemento, prova a convertire l'intera stringa in un numero
    try:
        number = int(issue)
        return number, None
    except ValueError:
        pass

    # Se non è possibile estrarre un numero, restituisci None per entrambi i valori
    return None, None

def _extract_number_and_supplment_from_issue_element(issue):

    number = None
    supplement = None

    if issue is not None:
        # Supponiamo che l'elemento issue sia una stringa con formato "numero-supplemento"
        parts = issue.split('-')
        if len(parts) > 0:
            number = parts[0]
        if len(parts) > 1:
            supplement = parts[1]

    return number, supplement

def _extract_number_and_supplment_from_issue_element(issue):

    # Split the issue into parts based on spaces
    parts = issue.split()

    # Initialize number and supplement
    number = None
    supplement = None

    # Iterate through the parts to find the number and supplement
    for part in parts:
        if part.isdigit():
            number = int(part)
        else:
            supplement = part

    return number, supplement

def _extract_number_and_supplment_from_issue_element(issue):

    # Rimuovi spazi bianchi e separa il numero dal supplemento
    issue = issue.strip()
    number_part = ''
    supplment_part = ''

    # Itera attraverso i caratteri per separare numero e supplemento
    for char in issue:
        if char.isdigit():
            number_part += char
        else:
            supplment_part += char

    # Converti il numero in intero, se presente
    number = int(number_part) if number_part else None

    return number, supplment_part.strip()

